import{_ as t,o as r,c as a,ag as o}from"./chunks/framework.DXGyWiRo.js";const l="/assets/image-20260219214802523.CtZDKiG8.png",s="/assets/image-20260219221920478.CYFcZJ1U.png",n="/assets/image-20260219224811534.Dgas5o4H.png",i="/assets/image-20260219234656532.CrpWooBM.png",f=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ES/Stm32/Stm32开发/开发环境.md","filePath":"ES/Stm32/Stm32开发/开发环境.md","lastUpdated":1775898880000}'),m={name:"ES/Stm32/Stm32开发/开发环境.md"};function c(p,e,d,h,u,b){return r(),a("div",null,[...e[0]||(e[0]=[o('<h2 id="keil-mdk" tabindex="-1">Keil MDK <a class="header-anchor" href="#keil-mdk" aria-label="Permalink to &quot;Keil MDK&quot;">​</a></h2><p>Keil MDK（<a href="https://www.keil.com/download/product/" target="_blank" rel="noreferrer">下载地址</a>）是 arm 公司一款经典且强大的嵌入式 IDE，它支持包括STM32在内的大多数 Cortex-M 系列微控制器的开发，集成了强大的编译器（5.36版本之后不提供AC5编译器），调试器与包管理工具，能够一站式完成代码的编写，编译，与调试。缺点是仅支持 Windows 平台，且界面复古，代码提示落后。详细操作见<a href="https://developer.arm.com/documentation/101407/0540" target="_blank" rel="noreferrer">用户指南</a>。</p><p><img src="'+l+'" alt="image-20260219214802523" class="img-scale-50"></p><h2 id="eide" tabindex="-1">EIDE <a class="header-anchor" href="#eide" aria-label="Permalink to &quot;EIDE&quot;">​</a></h2><p><a href="https://em-ide.com/zh-cn/docs/intro/" target="_blank" rel="noreferrer">Embedded IDE</a>是一个 VScode 插件，能够用于STM32，8051等单片机开发。具有现代的 UI 与智能的代码提示，支持跨平台，一键导入Keil项目，支持多种开发工具等优点。但插件本身并不集成编译器，需要自行下载配置工具链，针对 STM32 的调试基于<a href="https://github.com/Marus/cortex-debug" target="_blank" rel="noreferrer">Cortex-Debug</a>。</p><h2 id="stm32cube" tabindex="-1">STM32Cube <a class="header-anchor" href="#stm32cube" aria-label="Permalink to &quot;STM32Cube&quot;">​</a></h2><p>STM32Cube 是 ST 公司为 STM32 打造的软件生态，用以给 ST 的 MCU 和 MPU 提供完整<a href="https://www.st.com/content/st_com/en/stm32-mcu-developer-zone/software-development-tools.html" target="_blank" rel="noreferrer">软件解决方案</a>。</p><ul><li><a href="https://www.st.com/en/development-tools/st-mcu-finder-pc.html" target="_blank" rel="noreferrer"><strong>ST MCU Finder</strong></a>**：**STM32和STM8产品线的选型工具。</li><li><a href="https://www.st.com/en/development-tools/stm32cubemx.html" target="_blank" rel="noreferrer"><strong>STM32CubeMX</strong></a>**：**图形化配置工具。</li><li><a href="https://www.st.com/en/development-tools/stm32cubeide.html" target="_blank" rel="noreferrer"><strong>STM32CubeIDE</strong></a>**：**ST家的集成开发工具IDE。</li><li><a href="https://www.st.com/en/development-tools/stm32cubeprog.html" target="_blank" rel="noreferrer"><strong>STM32CubeProgrammer</strong></a><strong>：</strong> 支持图形化和命令行的烧录工具。</li><li><a href="https://www.st.com/en/development-tools/stm32cubemonitor.html" target="_blank" rel="noreferrer"><strong>STM32CubeMonitor</strong></a><strong>：</strong> 监测工具套装。</li></ul><p><img src="'+s+'" alt="image-20260219221920478"></p><h3 id="stm32cubemx" tabindex="-1">STM32CubeMX <a class="header-anchor" href="#stm32cubemx" aria-label="Permalink to &quot;STM32CubeMX&quot;">​</a></h3><p>STM32CubeMX（<a href="https://www.st.com/stm32cubemx" target="_blank" rel="noreferrer">下载地址</a> ）是一种图形工具，能给通过图形化的方式配置生成初始化C代码，能够集成FreeRTOS，TouchGFX等中间件。6.10版本之前需要提前安装<a href="https://www.java.com/zh_CN/download/windows-64bit.jsp" target="_blank" rel="noreferrer">Java运行库</a> ，之后的版本内置了一个 JRE 无需额外安装。</p><ul><li>Help 选项卡下的 Help 选项是对用版本CubeMX使用说明。</li><li>Help 选项卡下的 Embedded S0ftwa re Packages Manager 可用于下载固件库与各类第三方库。</li><li>Help 选项卡下的 Connection &amp; Updates 用于设置固件下载路径，固件更新检查设置，和代理设置。</li></ul><h3 id="stm32cube-for-vs-code" tabindex="-1">STM32Cube for VS Code <a class="header-anchor" href="#stm32cube-for-vs-code" aria-label="Permalink to &quot;STM32Cube for VS Code&quot;">​</a></h3><p>STM32Cube for VS Code 是一个 VS Code 插件。具有以下特点：</p><ul><li>使用开源工具链。</li><li>具有智能代码导航、代码补全、AI辅助。</li><li>基于 CMake 和 Ninja 的构建系统。</li><li>支持 ST-LINK 和 JLink 调试器。</li><li>与 STM32Cube 中其他软件高度适配程度。</li><li>具有图形化的 .map 文件分析工具。</li></ul><p><img src="'+n+'" alt="image-20260219224811534"></p><p>缺点是软件仍在开发阶段并不成熟。详细操作见用户指南：</p><p><img src="'+i+'" alt="image-20260219234656532" class="img-scale-50"></p><p><a href="https://shequ.stmicroelectronics.cn/thread-868922-1-1.html" target="_blank" rel="noreferrer">STM32CubeIDE for VS Code配置</a></p>',19)])])}const S=t(m,[["render",c]]);export{f as __pageData,S as default};
